import{_ as o,o as t,c as a,ag as n}from"./chunks/framework.C9sp7nFj.js";const p=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md","lastUpdated":1776620726000}'),r={name:"guide/troubleshooting.md"};function i(s,e,l,h,c,d){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>The fixes we recommend most often.</p><h2 id="login-pin" tabindex="-1">Login &amp; PIN <a class="header-anchor" href="#login-pin" aria-label="Permalink to &quot;Login &amp; PIN&quot;">​</a></h2><h3 id="that-email-or-password-didn-t-match" tabindex="-1">&quot;That email or password didn&#39;t match.&quot; <a class="header-anchor" href="#that-email-or-password-didn-t-match" aria-label="Permalink to &quot;&quot;That email or password didn&#39;t match.&quot;&quot;">​</a></h3><ul><li>Check for typos, especially in the domain (<code>.com</code> vs <code>.in</code>)</li><li>The eye icon in the password field lets you see what you typed</li><li>Caps Lock / auto-caps can silently uppercase characters</li><li>If still stuck, ask HR to reset your password from the Frappe Desk</li></ul><h3 id="too-many-wrong-pin-attempts" tabindex="-1">&quot;Too many wrong PIN attempts.&quot; <a class="header-anchor" href="#too-many-wrong-pin-attempts" aria-label="Permalink to &quot;&quot;Too many wrong PIN attempts.&quot;&quot;">​</a></h3><p>Five wrong PINs in a row locks you out. You&#39;re taken back to the login screen — sign in with your password and set a new PIN.</p><h3 id="forgot-my-pin" tabindex="-1">Forgot my PIN <a class="header-anchor" href="#forgot-my-pin" aria-label="Permalink to &quot;Forgot my PIN&quot;">​</a></h3><p>Tap <strong>Forgot PIN</strong> on the PIN screen → log in with password → set a new PIN.</p><h3 id="the-pin-screen-won-t-accept-my-pin-even-though-i-m-sure-it-s-right" tabindex="-1">The PIN screen won&#39;t accept my PIN even though I&#39;m sure it&#39;s right <a class="header-anchor" href="#the-pin-screen-won-t-accept-my-pin-even-though-i-m-sure-it-s-right" aria-label="Permalink to &quot;The PIN screen won&#39;t accept my PIN even though I&#39;m sure it&#39;s right&quot;">​</a></h3><ul><li>You may have an old cached PIN from a previous account. Tap <strong>Forgot PIN</strong> → login with password → set the PIN fresh.</li><li>If you changed your password recently, the old PIN stops working — same fix.</li></ul><h2 id="check-in" tabindex="-1">Check-in <a class="header-anchor" href="#check-in" aria-label="Permalink to &quot;Check-in&quot;">​</a></h2><h3 id="can-t-get-gps-grant-location-permission-then-tap-check-in-again" tabindex="-1">&quot;Can&#39;t get GPS. Grant location permission, then tap Check In again.&quot; <a class="header-anchor" href="#can-t-get-gps-grant-location-permission-then-tap-check-in-again" aria-label="Permalink to &quot;&quot;Can&#39;t get GPS. Grant location permission, then tap Check In again.&quot;&quot;">​</a></h3><p>Android Settings → Apps → <strong>Fateh HR Demo</strong> → Permissions → <strong>Location</strong> → <strong>Allow all the time</strong> (or at least &quot;While using the app&quot;).</p><h3 id="finding-your-location-just-sits-there" tabindex="-1">&quot;Finding your location…&quot; just sits there <a class="header-anchor" href="#finding-your-location-just-sits-there" aria-label="Permalink to &quot;&quot;Finding your location…&quot; just sits there&quot;">​</a></h3><p>GPS fix can take 10–30 seconds indoors. Try:</p><ul><li>Step outside / near a window</li><li>Make sure Location services are ON in Android&#39;s quick settings</li><li>Turn on High Accuracy GPS mode (Android Settings → Location → Google Location Accuracy)</li></ul><h3 id="selfie-screen-is-blank-camera-error" tabindex="-1">Selfie screen is blank / camera error <a class="header-anchor" href="#selfie-screen-is-blank-camera-error" aria-label="Permalink to &quot;Selfie screen is blank / camera error&quot;">​</a></h3><p>Android Settings → Apps → Fateh HR Demo → Permissions → <strong>Camera</strong> → Allow.</p><h3 id="check-in-recorded-but-appears-with-the-wrong-time" tabindex="-1">Check-in recorded but appears with the wrong time <a class="header-anchor" href="#check-in-recorded-but-appears-with-the-wrong-time" aria-label="Permalink to &quot;Check-in recorded but appears with the wrong time&quot;">​</a></h3><ul><li>All times are shown in <strong>your phone&#39;s timezone</strong>. If your phone&#39;s clock is wrong, so will the display be. Android Settings → System → Date &amp; time → <strong>Set automatically</strong> ON.</li><li>ERP (Frappe Desk) shows times in the <strong>company&#39;s timezone</strong> — those will differ from your phone by the timezone offset. That&#39;s normal and both are correct.</li></ul><h2 id="offline-sync" tabindex="-1">Offline / sync <a class="header-anchor" href="#offline-sync" aria-label="Permalink to &quot;Offline / sync&quot;">​</a></h2><h3 id="sync-bar-shows-3-sync-errors" tabindex="-1">Sync bar shows &quot;3 sync errors&quot; <a class="header-anchor" href="#sync-bar-shows-3-sync-errors" aria-label="Permalink to &quot;Sync bar shows &quot;3 sync errors&quot;&quot;">​</a></h3><p>Tap the bar → <strong>Sync Errors</strong> screen → tap <strong>Retry</strong> on each row. Most errors are transient network issues.</p><p>If a row keeps failing after retries:</p><ol><li>Screenshot the error message</li><li>Send to HR / IT</li></ol><h3 id="the-sync-bar-never-says-synced-now" tabindex="-1">The sync bar never says &quot;Synced now&quot; <a class="header-anchor" href="#the-sync-bar-never-says-synced-now" aria-label="Permalink to &quot;The sync bar never says &quot;Synced now&quot;&quot;">​</a></h3><ul><li>Check that your device has network (you might be connected to WiFi with no internet)</li><li>Force-close the app (recent apps → swipe up) and reopen</li><li>Try a different network (WiFi vs mobile data)</li></ul><h3 id="my-offline-check-in-didn-t-sync" tabindex="-1">My offline check-in didn&#39;t sync <a class="header-anchor" href="#my-offline-check-in-didn-t-sync" aria-label="Permalink to &quot;My offline check-in didn&#39;t sync&quot;">​</a></h3><ul><li>Open the <strong>Check-in history</strong> — if it says <strong>&quot;Pending sync&quot;</strong> next to the entry, it&#39;s still queued. Get online, watch the sync bar.</li><li>If it&#39;s not in history at all, check the <strong>Sync Errors</strong> screen — it may have failed. Retry from there.</li></ul><h2 id="payslip-pdf-download" tabindex="-1">Payslip PDF download <a class="header-anchor" href="#payslip-pdf-download" aria-label="Permalink to &quot;Payslip PDF download&quot;">​</a></h2><h3 id="download-button-does-nothing" tabindex="-1">&quot;Download&quot; button does nothing <a class="header-anchor" href="#download-button-does-nothing" aria-label="Permalink to &quot;&quot;Download&quot; button does nothing&quot;">​</a></h3><ul><li>On old APK versions (pre-1.0.13), native download was broken. <strong>Update to the latest APK</strong> — your HR team will have the download link.</li><li>After the update, tap Download → you should see <strong>&quot;Saved to Documents.&quot;</strong> confirmation.</li></ul><h3 id="i-can-t-find-the-downloaded-pdf" tabindex="-1">I can&#39;t find the downloaded PDF <a class="header-anchor" href="#i-can-t-find-the-downloaded-pdf" aria-label="Permalink to &quot;I can&#39;t find the downloaded PDF&quot;">​</a></h3><p>Open any file manager (Google Files, Samsung My Files, etc.) → <strong>Documents</strong> folder. The filename looks like <code>Sal_Slip_None_00006.pdf</code>.</p><h3 id="share-opens-but-doesn-t-have-pdf-attached" tabindex="-1">Share opens but doesn&#39;t have PDF attached <a class="header-anchor" href="#share-opens-but-doesn-t-have-pdf-attached" aria-label="Permalink to &quot;Share opens but doesn&#39;t have PDF attached&quot;">​</a></h3><p>Some older Android versions don&#39;t support the share-file API. In that case the app falls back to Download. Look for the PDF in your Documents folder, then share it from the file manager.</p><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><h3 id="app-feels-slow-to-open" tabindex="-1">App feels slow to open <a class="header-anchor" href="#app-feels-slow-to-open" aria-label="Permalink to &quot;App feels slow to open&quot;">​</a></h3><ul><li>Clear background apps to free memory (recent apps → clear all)</li><li>Reboot the phone</li><li>On the web app: clear browser cache, or try a fresh tab</li></ul><h3 id="something-went-wrong-screen" tabindex="-1">&quot;Something went wrong&quot; screen <a class="header-anchor" href="#something-went-wrong-screen" aria-label="Permalink to &quot;&quot;Something went wrong&quot; screen&quot;">​</a></h3><p>This is Vue&#39;s error boundary. It means an unhandled error occurred. Steps:</p><ol><li>Close the app fully and reopen</li><li>If it happens again, note what you were doing and tell HR / IT — they can check the Error Log on the Frappe Desk.</li></ol><h3 id="data-on-mobile-doesn-t-match-the-erp-desk" tabindex="-1">Data on mobile doesn&#39;t match the ERP Desk <a class="header-anchor" href="#data-on-mobile-doesn-t-match-the-erp-desk" aria-label="Permalink to &quot;Data on mobile doesn&#39;t match the ERP Desk&quot;">​</a></h3><p>After any change on the Desk (new leave allocation, payslip created, policy update), the mobile app picks it up <strong>next time you open the relevant screen</strong> or <strong>pull to refresh</strong> (if available). Force-close and reopen the app to pull fresh data.</p><h2 id="still-stuck" tabindex="-1">Still stuck? <a class="header-anchor" href="#still-stuck" aria-label="Permalink to &quot;Still stuck?&quot;">​</a></h2><ol><li><strong>Note which APK version</strong> — tap <strong>More</strong> → scroll to the bottom, the version is shown (e.g. <code>1.0.19</code>)</li><li><strong>Screenshot the error</strong> or the screen you&#39;re stuck on</li><li><strong>Send both to HR / IT</strong> along with a brief description</li></ol><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/faq">FAQ</a></li><li><a href="/guide/getting-started">Getting started</a></li></ul>',49)])])}const g=o(r,[["render",i]]);export{p as __pageData,g as default};
